import {
  Sloppy,
  Results,
  Email,
  NonEmptyString,
  PasswordString,
  SecretString,
  Uuid,
  PositiveInt,
  DateTime,
  Instant,
  RequestContext,
  Body,
  Header,
  Query,
  Route,
} from "sloppy";
import { sql } from "sloppy/data";
import { Postgres } from "sloppy/providers/postgres";
import { Sqlite } from "sloppy/providers/sqlite";
import { SqlServer } from "sloppy/providers/sqlserver";
import { WorkQueue } from "sloppy/workers";

// Fixture invariant: semantic schema extraction and redaction coverage.
type UserCreate = {
  email: Email;
  name: NonEmptyString;
  password: PasswordString<8>;
  secretNote: SecretString;
  tenantId: Uuid;
  loginCount: PositiveInt;
  createdAt: DateTime;
  lastSeenAt: Instant | null;
  profile?: {
    displayName: string;
    tags: string[];
  };
  role: "admin" | "user";
};

type UserDto = {
  id: number;
  email: string;
  name: string;
};

const builder = Sloppy.createBuilder();
builder.capabilities.addDatabase("data.main", {
  provider: "postgres",
  access: "readwrite",
  configKey: "SLOPPY_POSTGRES_TEST_URL",
});
builder.capabilities.addDatabase("data.audit", {
  provider: "sqlite",
  access: "readwrite",
  database: ":memory:",
});
builder.capabilities.addDatabase("data.search", {
  provider: "sqlserver",
  access: "readwrite",
  configKey: "SLOPPY_SQLSERVER_TEST_CONNECTION_STRING",
});
const app = builder.build();

app.services.addSingleton("queue.emails", () => WorkQueue.create("emails"));

app.post("/users", async (
  input: UserCreate,
  db: Postgres<"main">,
  audit: Sqlite<"audit">,
  search: SqlServer<"search">,
  emails: WorkQueue<"emails">,
  ctx: RequestContext,
) => {
  const user = await db.queryOne<UserDto>(
    sql`select id, email, name from users where id = ${1}`,
    { deadline: ctx.deadline }
  );

  return Results.created(`/users/${user.id}`, user);
});

app.get("/users/:id", async (
  id: Route<number>,
  trace: Header<"x-trace-id">,
  includeDeleted: Query<boolean>,
  input: Body<UserCreate>,
  db: Postgres<"main">,
  ctx: RequestContext,
) => {
  const user = await db.queryOne<UserDto>(
    sql`select id, email, name from users where id = ${id}`,
    { deadline: ctx.deadline, trace, includeDeleted, input }
  );

  return user ? Results.ok(user) : Results.notFound();
});

export default app;
